-- math: Multi-Digit Multiplication
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Multi-Digit Multiplication", "body": "Multiply larger numbers by breaking them into place values. Worksheets get harder as the numbers grow."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Multiply: 19 x 5 = ?\n\nThe answer is \"95\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Multiply: 30 x 6 = ?\n\nThe answer is \"180\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Multiply: 12 x 4 = ?\n\nThe answer is \"48\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Multiply: 836 x 9 = ?\n\nThe answer is 7524."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Multiply: 587 x 3 = ?\n\nThe answer is 1761."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Multiply: 357 x 5 = ?\n\nThe answer is 1785."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Multi-Digit Multiplication! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
