-- math: Decimal Place Value
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Decimal Place Value", "body": "Each digit after the decimal point has a smaller place value: tenths, hundredths, thousandths."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the value of the digit 2 in 8.2?\n\nThe answer is \"0.2\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the value of the digit 3 in 3.4?\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the value of the digit 2 in 2.8?\n\nThe answer is \"2\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What is the value of the digit 8 in 1.8?", "choices": [{"id": "a", "label": "80"}, {"id": "b", "label": "0.8"}, {"id": "c", "label": "8"}, {"id": "d", "label": "0.08"}], "answer": "b", "explanation": "Yes! The answer is \"0.8\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What is the value of the digit 4 in 3.4?", "choices": [{"id": "a", "label": "0.04"}, {"id": "b", "label": "40"}, {"id": "c", "label": "4"}, {"id": "d", "label": "0.4"}], "answer": "d", "explanation": "Yes! The answer is \"0.4\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What is the value of the digit 1 in 1.14?", "choices": [{"id": "a", "label": "0.1"}, {"id": "b", "label": "10"}, {"id": "c", "label": "1"}, {"id": "d", "label": "2"}], "answer": "c", "explanation": "Yes! The answer is \"1\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Decimal Place Value! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$decimal-place-value$tl$ and t.grade_level = 5);

