-- math: Volume
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Volume", "body": "The volume of a box is length x width x height, measured in cubic units."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A box is 4 units long, 2 wide, and 3 tall. What is its volume in cubic units?  (length x width x height)\n\nThe answer is \"24\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A box is 4 units long, 4 wide, and 2 tall. What is its volume in cubic units?  (length x width x height)\n\nThe answer is \"32\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A box is 3 units long, 3 wide, and 4 tall. What is its volume in cubic units?  (length x width x height)\n\nThe answer is \"36\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  A box is 6 units long, 5 wide, and 6 tall. What is its volume in cubic units?  (length x width x height)\n\nThe answer is 180."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  A box is 3 units long, 2 wide, and 6 tall. What is its volume in cubic units?  (length x width x height)\n\nThe answer is 36."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  A box is 3 units long, 2 wide, and 3 tall. What is its volume in cubic units?  (length x width x height)\n\nThe answer is 18."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Volume! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
