-- science: Matter & Its Properties
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Matter & Its Properties", "body": "Matter is anything with mass and volume; we identify materials by their properties."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Everything around us that has mass and takes up space is called:\n\nThe answer is \"matter\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The three common states of matter are solid, liquid, and:\n\nThe answer is \"gas\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which is a property you can measure about matter?\n\nThe answer is \"mass\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Even a gas like air is made of tiny particles too small to:", "choices": [{"id": "a", "label": "weigh ever"}, {"id": "b", "label": "exist"}, {"id": "c", "label": "move"}, {"id": "d", "label": "see"}], "answer": "d", "explanation": "Yes! The answer is \"see\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A balloon filled with air shows that gas has:", "choices": [{"id": "a", "label": "no mass at all"}, {"id": "b", "label": "mass and takes up space"}, {"id": "c", "label": "no volume"}, {"id": "d", "label": "color only"}], "answer": "b", "explanation": "Yes! The answer is \"mass and takes up space\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which tool measures the mass of an object?", "choices": [{"id": "a", "label": "a ruler"}, {"id": "b", "label": "a thermometer"}, {"id": "c", "label": "a balance"}, {"id": "d", "label": "a clock"}], "answer": "c", "explanation": "Yes! The answer is \"a balance\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Matter & Its Properties! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$matter-and-properties$tl$ and t.grade_level = 5);

-- science: Mixtures & Solutions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Mixtures & Solutions", "body": "Mixtures can be separated; when a solid dissolves evenly in a liquid it forms a solution."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  When you stir sand into water, you make a:\n\nThe answer is \"mixture\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  When sugar dissolves completely in water, it forms a:\n\nThe answer is \"solution\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  In a solution, the dissolved substance seems to:\n\nThe answer is \"disappear (spread evenly)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which mixture can be separated by a strainer or filter?", "choices": [{"id": "a", "label": "salt fully dissolved in water"}, {"id": "b", "label": "sugar water"}, {"id": "c", "label": "sand and water"}, {"id": "d", "label": "air"}], "answer": "c", "explanation": "Yes! The answer is \"sand and water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "How can you separate salt from salt water?", "choices": [{"id": "a", "label": "use a magnet"}, {"id": "b", "label": "use a strainer"}, {"id": "c", "label": "freeze it once"}, {"id": "d", "label": "let the water evaporate"}], "answer": "d", "explanation": "Yes! The answer is \"let the water evaporate\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A magnet can be used to separate iron filings from:", "choices": [{"id": "a", "label": "salt water"}, {"id": "b", "label": "sugar"}, {"id": "c", "label": "air"}, {"id": "d", "label": "sand"}], "answer": "d", "explanation": "Yes! The answer is \"sand\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Mixtures & Solutions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
