-- science: Conservation of Matter
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Conservation of Matter", "body": "In ordinary changes, matter is never created or destroyed - total mass stays the same."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  When you mix two things, the total mass:\n\nThe answer is \"stays the same\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  If 50 g of water freezes into ice, the ice weighs about:\n\nThe answer is \"50 g\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Matter is never created or destroyed in ordinary changes - it is:\n\nThe answer is \"conserved\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When sugar dissolves in water, the mass of the solution equals:", "choices": [{"id": "a", "label": "sugar + water"}, {"id": "b", "label": "just the water"}, {"id": "c", "label": "just the sugar"}, {"id": "d", "label": "zero"}], "answer": "a", "explanation": "Yes! The answer is \"sugar + water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "If ice melts in a sealed cup, the water's mass is:", "choices": [{"id": "a", "label": "less"}, {"id": "b", "label": "more"}, {"id": "c", "label": "the same as the ice"}, {"id": "d", "label": "zero"}], "answer": "c", "explanation": "Yes! The answer is \"the same as the ice\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Burning a log seems to lose mass, but the gases released still count, so matter is:", "choices": [{"id": "a", "label": "conserved"}, {"id": "b", "label": "destroyed"}, {"id": "c", "label": "created"}, {"id": "d", "label": "gone"}], "answer": "a", "explanation": "Yes! The answer is \"conserved\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Conservation of Matter! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
