-- science: Food Webs & Energy
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Food Webs & Energy", "body": "Energy flows from the Sun to producers to consumers; decomposers recycle nutrients."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Almost all the energy in an ecosystem starts with the:\n\nThe answer is \"Sun\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Plants are called producers because they:\n\nThe answer is \"make their own food\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An animal that eats plants is a:\n\nThe answer is \"herbivore\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An animal that eats other animals is a:", "choices": [{"id": "a", "label": "herbivore"}, {"id": "b", "label": "carnivore"}, {"id": "c", "label": "producer"}, {"id": "d", "label": "plant"}], "answer": "b", "explanation": "Yes! The answer is \"carnivore\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In a food chain, an arrow points in the direction that:", "choices": [{"id": "a", "label": "animals walk"}, {"id": "b", "label": "the wind blows"}, {"id": "c", "label": "energy flows"}, {"id": "d", "label": "water falls"}], "answer": "c", "explanation": "Yes! The answer is \"energy flows\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Decomposers like fungi and bacteria break down dead things and return nutrients to the:", "choices": [{"id": "a", "label": "sky"}, {"id": "b", "label": "soil"}, {"id": "c", "label": "Sun"}, {"id": "d", "label": "ocean only"}], "answer": "b", "explanation": "Yes! The answer is \"soil\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Food Webs & Energy! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
