-- science: How Plants Make Food
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: How Plants Make Food", "body": "Through photosynthesis, plants use sunlight, water, and air to make their own food."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Plants make their own food using sunlight in a process called:\n\nThe answer is \"photosynthesis\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Most of the material a plant uses to grow comes from:\n\nThe answer is \"air and water\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Plants take in carbon dioxide from the air through tiny openings in their:\n\nThe answer is \"leaves\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "During photosynthesis, plants release which gas that we breathe?", "choices": [{"id": "a", "label": "carbon dioxide"}, {"id": "b", "label": "helium"}, {"id": "c", "label": "smoke"}, {"id": "d", "label": "oxygen"}], "answer": "d", "explanation": "Yes! The answer is \"oxygen\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The green substance in leaves that captures sunlight is:", "choices": [{"id": "a", "label": "water"}, {"id": "b", "label": "chlorophyll"}, {"id": "c", "label": "sugar"}, {"id": "d", "label": "soil"}], "answer": "b", "explanation": "Yes! The answer is \"chlorophyll\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Plants store the energy they make as:", "choices": [{"id": "a", "label": "sunlight"}, {"id": "b", "label": "sugar (food)"}, {"id": "c", "label": "oxygen"}, {"id": "d", "label": "water"}], "answer": "b", "explanation": "Yes! The answer is \"sugar (food)\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about How Plants Make Food! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$: