-- science: Earth's Systems
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Earth's Systems", "body": "Earth's atmosphere, hydrosphere, geosphere, and biosphere constantly interact."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The layer of air surrounding Earth is the:\n\nThe answer is \"atmosphere\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  All of Earth's water - oceans, rivers, ice - makes up the:\n\nThe answer is \"hydrosphere\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Earth's rocks, soil, and land form the:\n\nThe answer is \"geosphere\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "All living things on Earth make up the:", "choices": [{"id": "a", "label": "atmosphere"}, {"id": "b", "label": "geosphere"}, {"id": "c", "label": "biosphere"}, {"id": "d", "label": "hydrosphere"}], "answer": "c", "explanation": "Yes! The answer is \"biosphere\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When rain (hydrosphere) helps a plant (biosphere) grow, two Earth systems are:", "choices": [{"id": "a", "label": "interacting"}, {"id": "b", "label": "disappearing"}, {"id": "c", "label": "stopping"}, {"id": "d", "label": "unrelated"}], "answer": "a", "explanation": "Yes! The answer is \"interacting\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Wind in the atmosphere shaping a sand dune shows the atmosphere affecting the:", "choices": [{"id": "a", "label": "biosphere only"}, {"id": "b", "label": "geosphere"}, {"id": "c", "label": "nothing"}, {"id": "d", "label": "Moon"}], "answer": "b", "explanation": "Yes! The answer is \"geosphere\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Earth's Systems! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
