update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Protecting Earth's Resources", "body": "People can protect Earth by reducing, reusing, recycling, and using renewable energy."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Using fewer resources and reusing items helps:\n\nThe answer is \"protect the environment\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The three R's that reduce waste are reduce, reuse, and:\n\nThe answer is \"recycle\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which is a renewable energy source?\n\nThe answer is \"sunlight\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Burning fossil fuels like coal and oil adds pollution and:", "choices": [{"id": "a", "label": "greenhouse gases"}, {"id": "b", "label": "clean air"}, {"id": "c", "label": "fresh water"}, {"id": "d", "label": "oxygen"}], "answer": "a", "explanation": "Yes! The answer is \"greenhouse gases\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Planting trees helps because trees clean the air and provide:", "choices": [{"id": "a", "label": "plastic"}, {"id": "b", "label": "gasoline"}, {"id": "c", "label": "metal"}, {"id": "d", "label": "oxygen and habitat"}], "answer": "d", "explanation": "Yes! The answer is \"oxygen and habitat\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which action best conserves water?", "choices": [{"id": "a", "label": "letting taps run"}, {"id": "b", "label": "watering pavement"}, {"id": "c", "label": "ignoring leaks"}, {"id": "d", "label": "fixing leaky faucets"}], "answer": "d", "explanation": "Yes! The answer is \"fixing leaky faucets\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Protecting Earth's Resources! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
