update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Patterns in the Sky", "body": "Earth's rotation and orbit cause day/night, seasons, shadows, and the Moon's phases."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The Sun appears to rise in the east and set in the:\n\nThe answer is \"west\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Day and night are caused by Earth:\n\nThe answer is \"rotating (spinning) once a day\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The seasons are caused by Earth's tilt as it:\n\nThe answer is \"orbits the Sun\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Stars appear to move across the night sky because Earth:", "choices": [{"id": "a", "label": "is exploding"}, {"id": "b", "label": "is shrinking"}, {"id": "c", "label": "makes the stars"}, {"id": "d", "label": "is rotating"}], "answer": "d", "explanation": "Yes! The answer is \"is rotating\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A shadow from a stick is longest when the Sun is:", "choices": [{"id": "a", "label": "directly overhead"}, {"id": "b", "label": "gone"}, {"id": "c", "label": "behind the Moon"}, {"id": "d", "label": "low in the sky"}], "answer": "d", "explanation": "Yes! The answer is \"low in the sky\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "At noon, when the Sun is highest, shadows are:", "choices": [{"id": "a", "label": "longest"}, {"id": "b", "label": "shortest"}, {"id": "c", "label": "gone forever"}, {"id": "d", "label": "pointing up"}], "answer": "b", "explanation": "Yes! The answer is \"shortest\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Patterns in the Sky! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$