update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Gravity", "body": "Gravity is a force that pulls objects toward Earth's center and holds planets in orbit."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The force that pulls objects toward Earth is:\n\nThe answer is \"gravity\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  When you drop a ball, gravity pulls it:\n\nThe answer is \"down toward Earth's center\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Gravity is what keeps the Moon in orbit around:\n\nThe answer is \"Earth\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Without gravity, objects on Earth would:", "choices": [{"id": "a", "label": "float away"}, {"id": "b", "label": "fall faster"}, {"id": "c", "label": "stay the same"}, {"id": "d", "label": "get heavier"}], "answer": "a", "explanation": "Yes! The answer is \"float away\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Weight is a measure of the pull of ____ on an object.", "choices": [{"id": "a", "label": "friction"}, {"id": "b", "label": "sound"}, {"id": "c", "label": "light"}, {"id": "d", "label": "gravity"}], "answer": "d", "explanation": "Yes! The answer is \"gravity\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Earth's gravity points toward Earth's:", "choices": [{"id": "a", "label": "the sky"}, {"id": "b", "label": "the Moon"}, {"id": "c", "label": "center"}, {"id": "d", "label": "the Sun"}], "answer": "c", "explanation": "Yes! The answer is \"center\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Gravity! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
