-- reading: Main Idea & Details
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Main Idea & Details", "body": "The main idea is a text's key point; supporting details explain and back it up."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"Sea otters are vital to kelp forests. They eat sea urchins, which would otherwise destroy the kelp.\" The main idea is that sea otters:\n\nThe answer is \"help protect kelp forests\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Volcanoes can be destructive, but volcanic ash also enriches soil and creates fertile farmland.\" The main idea is that volcanoes:\n\nThe answer is \"can be both harmful and helpful\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  In the otter passage, which is a supporting detail?\n\nThe answer is \"they eat sea urchins\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Recycling conserves resources by saving trees, reducing energy use, and cutting landfill waste.\" A supporting detail is that recycling:", "choices": [{"id": "a", "label": "reduces energy use"}, {"id": "b", "label": "is colorful"}, {"id": "c", "label": "is difficult"}, {"id": "d", "label": "is loud"}], "answer": "a", "explanation": "Yes! The answer is \"reduces energy use\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The main idea of a paragraph is usually:", "choices": [{"id": "a", "label": "its most important point"}, {"id": "b", "label": "the longest sentence"}, {"id": "c", "label": "the first word"}, {"id": "d", "label": "a random fact"}], "answer": "a", "explanation": "Yes! The answer is \"its most important point\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Honeybee numbers are falling due to pesticides, disease, and habitat loss, threatening the crops they pollinate.\" The main idea is that:", "choices": [{"id": "a", "label": "declining bees endanger our crops"}, {"id": "b", "label": "bees make honey"}, {"id": "c", "label": "bees sting"}, {"id": "d", "label": "flowers are pretty"}], "answer": "a", "explanation": "Yes! The answer is \"declining bees endanger our crops\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Main Idea & Details! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$main-idea-and-details$tl$ and t.grade_level = 5);

-- reading: Theme
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Theme", "body": "A theme is the lesson or message a story conveys, usually shown through what characters learn."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A theme is the:\n\nThe answer is \"lesson or message of a story\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"After failing many times, Mia finally built her robot by never giving up.\" A theme is:\n\nThe answer is \"perseverance pays off\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A story where a selfish king learns to share teaches a theme about:\n\nThe answer is \"generosity / kindness\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Theme is different from plot because theme is the:", "choices": [{"id": "a", "label": "sequence of events"}, {"id": "b", "label": "list of characters"}, {"id": "c", "label": "the setting only"}, {"id": "d", "label": "underlying message"}], "answer": "d", "explanation": "Yes! The answer is \"underlying message\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The two rivals worked together to survive the storm and became friends.\" A theme is:", "choices": [{"id": "a", "label": "cooperation / friendship"}, {"id": "b", "label": "enemies forever"}, {"id": "c", "label": "storms are fun"}, {"id": "d", "label": "ignore others"}], "answer": "a", "explanation": "Yes! The answer is \"cooperation / friendship\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A common theme in many fables is:", "choices": [{"id": "a", "label": "honesty is important"}, {"id": "b", "label": "lying wins"}, {"id": "c", "label": "be cruel"}, {"id": "d", "label": "never learn"}], "answer": "a", "explanation": "Yes! The answer is \"honesty is important\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Theme! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$theme$tl$ and t.grade_level = 5);

-- reading: Summarizing
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Summarizing", "body": "A summary retells the main idea and key details briefly, in your own words."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A good summary includes the main idea and the:\n\nThe answer is \"most important details\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A summary should be:\n\nThe answer is \"shorter than the original\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  When summarizing, you should leave out:\n\nThe answer is \"unimportant details\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A summary should be written in:", "choices": [{"id": "a", "label": "the author's exact words"}, {"id": "b", "label": "a secret code"}, {"id": "c", "label": "your own words"}, {"id": "d", "label": "no words"}], "answer": "c", "explanation": "Yes! The answer is \"your own words\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The first step to summarizing is to:", "choices": [{"id": "a", "label": "identify the main idea"}, {"id": "b", "label": "copy the whole text"}, {"id": "c", "label": "read only the title"}, {"id": "d", "label": "skip to the end"}], "answer": "a", "explanation": "Yes! The answer is \"identify the main idea\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A summary of a story should keep events in:", "choices": [{"id": "a", "label": "random order"}, {"id": "b", "label": "reverse only"}, {"id": "c", "label": "no order"}, {"id": "d", "label": "the correct order"}], "answer": "d", "explanation": "Yes! The answer is \"the correct order\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Summarizing! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$summarizing$tl$ and t.grade_level = 5);

-- reading: Making Inferences
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Making Inferences", "body": "An inference is a conclusion drawn from text clues plus what you already know."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An inference is a conclusion based on:\n\nThe answer is \"clues plus what you know\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Maria grabbed her umbrella and rain boots before leaving.\" You can infer:\n\nThe answer is \"it is raining or about to\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Jake's stomach growled as he stared at the clock near noon.\" Infer that Jake is:\n\nThe answer is \"hungry\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"The streets were empty and every shop was dark.\" You can infer it is:", "choices": [{"id": "a", "label": "a busy afternoon"}, {"id": "b", "label": "a parade"}, {"id": "c", "label": "lunchtime"}, {"id": "d", "label": "very early or very late"}], "answer": "d", "explanation": "Yes! The answer is \"very early or very late\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An author who doesn't state everything expects the reader to:", "choices": [{"id": "a", "label": "infer meaning from clues"}, {"id": "b", "label": "skip the text"}, {"id": "c", "label": "memorize it"}, {"id": "d", "label": "ignore details"}], "answer": "a", "explanation": "Yes! The answer is \"infer meaning from clues\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Tia hugged the trophy and beamed at the cheering crowd.\" Infer that Tia:", "choices": [{"id": "a", "label": "lost and is sad"}, {"id": "b", "label": "is bored"}, {"id": "c", "label": "won and is proud"}, {"id": "d", "label": "is afraid"}], "answer": "c", "explanation": "Yes! The answer is \"won and is proud\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Making Inferences! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
