-- reading: Character Analysis
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Character Analysis", "body": "Understand characters through their words, actions, thoughts, and how they change."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  To understand a character, pay attention to their words, thoughts, and:\n\nThe answer is \"actions\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"Lia gave her lunch to the new student and offered to show him around.\" Lia is:\n\nThe answer is \"kind and welcoming\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A character who changes and grows during a story is called:\n\nThe answer is \"dynamic\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"No matter how many times he failed, Sam tried again.\" Sam is:", "choices": [{"id": "a", "label": "lazy"}, {"id": "b", "label": "determined"}, {"id": "c", "label": "fearful"}, {"id": "d", "label": "careless"}], "answer": "b", "explanation": "Yes! The answer is \"determined\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A character's motivation is the:", "choices": [{"id": "a", "label": "their height"}, {"id": "b", "label": "their clothes"}, {"id": "c", "label": "reason they act"}, {"id": "d", "label": "their name"}], "answer": "c", "explanation": "Yes! The answer is \"reason they act\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She lied to avoid blame, then felt guilty all night.\" This shows the character has a:", "choices": [{"id": "a", "label": "conscience (sense of right and wrong)"}, {"id": "b", "label": "fear of dogs"}, {"id": "c", "label": "love of math"}, {"id": "d", "label": "new bike"}], "answer": "a", "explanation": "Yes! The answer is \"conscience (sense of right and wrong)\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Character Analysis! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
