update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Point of View", "body": "Point of view is the perspective a story is told from - first or third person."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A story told using 'I' and 'me' is written in:\n\nThe answer is \"first person\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A story told using 'he', 'she', and 'they' is in:\n\nThe answer is \"third person\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The narrator is the:\n\nThe answer is \"one telling the story\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"I couldn't believe my eyes as I opened the door.\" This is:", "choices": [{"id": "a", "label": "first person"}, {"id": "b", "label": "third person"}, {"id": "c", "label": "second person"}, {"id": "d", "label": "no narrator"}], "answer": "a", "explanation": "Yes! The answer is \"first person\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She wondered what was behind the door as he waited.\" This is:", "choices": [{"id": "a", "label": "first person"}, {"id": "b", "label": "second person"}, {"id": "c", "label": "third person"}, {"id": "d", "label": "fourth person"}], "answer": "c", "explanation": "Yes! The answer is \"third person\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Point of view is the:", "choices": [{"id": "a", "label": "page count"}, {"id": "b", "label": "setting"}, {"id": "c", "label": "title"}, {"id": "d", "label": "perspective the story is told from"}], "answer": "d", "explanation": "Yes! The answer is \"perspective the story is told from\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Point of View! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
