update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Text Structure", "body": "Authors organize texts as sequence, cause-effect, compare-contrast, or problem-solution."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A text that lists steps in order uses a ____ structure.\n\nThe answer is \"sequence (chronological)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A text that explains why something happens and the results uses:\n\nThe answer is \"cause and effect\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A text that tells how two things are alike and different uses:\n\nThe answer is \"compare and contrast\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A text that presents an issue and then ways to fix it uses:", "choices": [{"id": "a", "label": "sequence"}, {"id": "b", "label": "problem and solution"}, {"id": "c", "label": "description"}, {"id": "d", "label": "compare"}], "answer": "b", "explanation": "Yes! The answer is \"problem and solution\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Words like first, next, then, and finally signal a ____ structure.", "choices": [{"id": "a", "label": "compare"}, {"id": "b", "label": "sequence"}, {"id": "c", "label": "cause-effect"}, {"id": "d", "label": "problem-solution"}], "answer": "b", "explanation": "Yes! The answer is \"sequence\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Words like because, since, and as a result signal:", "choices": [{"id": "a", "label": "sequence"}, {"id": "b", "label": "cause and effect"}, {"id": "c", "label": "compare"}, {"id": "d", "label": "description"}], "answer": "b", "explanation": "Yes! The answer is \"cause and effect\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Text Structure! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
