update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Comparing Texts", "body": "Comparing texts on the same topic reveals how they are alike and different."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  To compare two texts means to find how they are:\n\nThe answer is \"alike\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  To contrast two texts means to find how they are:\n\nThe answer is \"different\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Two articles on sharks, one scary and one scientific, differ mainly in their:\n\nThe answer is \"tone / purpose\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read accounts of the same storm by a sailor and a scientist; they likely differ in:", "choices": [{"id": "a", "label": "the date it happened"}, {"id": "b", "label": "whether it was a storm"}, {"id": "c", "label": "point of view and detail"}, {"id": "d", "label": "the planet"}], "answer": "c", "explanation": "Yes! The answer is \"point of view and detail\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A Venn diagram is a tool used to:", "choices": [{"id": "a", "label": "tell time"}, {"id": "b", "label": "measure mass"}, {"id": "c", "label": "compare and contrast"}, {"id": "d", "label": "spell words"}], "answer": "c", "explanation": "Yes! The answer is \"compare and contrast\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Two recipes for bread are alike because both:", "choices": [{"id": "a", "label": "give steps to make bread"}, {"id": "b", "label": "are mystery novels"}, {"id": "c", "label": "are about cars"}, {"id": "d", "label": "are poems"}], "answer": "a", "explanation": "Yes! The answer is \"give steps to make bread\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Comparing Texts! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
